def tsp(dist):
    """
    dist: n x n distance matrix (dist[i][j] = cost from i to j)
    Returns minimum cost of visiting all cities exactly once and returning to 0.
    """
    n    = len(dist)
    INF  = float('inf')
    full = (1 << n) - 1
    # dp[mask][v] = min cost to visit cities in mask, ending at city v
    dp = [[INF] * n for _ in range(1 << n)]
    dp[1][0] = 0   # start at city 0, mask = {0}

    for mask in range(1, 1 << n):
        for u in range(n):
            if dp[mask][u] == INF: continue
            if not (mask >> u & 1): continue  # u must be in mask
            for v in range(n):
                if mask >> v & 1: continue    # v not yet visited
                new_mask = ___________
                new_cost = dp[mask][u] + dist[u][v]
                if new_cost < dp[new_mask][v]:
                    dp[new_mask][v] = new_cost

    return min(dp[full][u] + dist[u][0] for u in range(1, n))
